// Helper: Get challenge for specific date
export function getChallengeForDate(date: Date): GiornataSpeciale | null {
  const giorno = date.getDate();
  const mese = date.getMonth() + 1;
  
  // Prima cerca nelle giornate speciali fisse
  const fixedChallenge = giornateSpeciali.find(g => g.giorno === giorno && g.mese === mese);
  if (fixedChallenge) return fixedChallenge;
  
  // Poi cerca negli eventi stagionali (equinozi, solstizi, etc.)
  const seasonalEvent = getSeasonalEventForDate(date);
  if (seasonalEvent) {
    // Converti evento stagionale in challenge
    return {
      giorno: date.getDate(),
      mese: date.getMonth() + 1,
      tipo: 'stagionale' as const,
      evento: seasonalEvent.name,
      hashtag: [seasonalEvent.type === 'equinox' ? 'Equinozio' : 'Solstizio'],
      
      challenge: {
        titolo: `${seasonalEvent.name} Challenge`,
        descrizione: seasonalEvent.description,
        difficolta: 'facile',
        
        azioni: seasonalEvent.consiglioOrto ? [
          {
            emoji: seasonalEvent.emoji,
            azione: seasonalEvent.consiglioOrto,
            perche: 'Tradizione contadina e astronomia'
          }
        ] : [],
        
        badge: {
          nome: `Celebratore ${seasonalEvent.name}`,
          emoji: seasonalEvent.emoji,
          descrizione: `Hai celebrato ${seasonalEvent.name}`
        },
        
        punti: 80,
        
        shareText: `${seasonalEvent.name}! ${seasonalEvent.emoji} #OrtoMio`
      },
      
      consiglioOrto: seasonalEvent.consiglioOrto,
      proverbio: seasonalEvent.proverbio
    };
  }
  
  return null;
}

// Helper: Get all challenges for a month
export function getChallengesForMonth(mese: number): GiornataSpeciale[] {
  return giornateSpeciali.filter(g => g.mese === mese);
}

// Helper: Get challenges by type
export function getChallengesByType(tipo: GiornataSpeciale['tipo']): GiornataSpeciale[] {
  return giornateSpeciali.filter(g => g.tipo === tipo);
}

